#include<bits/stdc++.h>
using namespace std;
const int N=10010;
int dfn[N],low[N],dfncnt,scc[N],siz[N],scccnt;
bool instk[N];
vector<int> mp[N];
stack<int> s;
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    instk[x]=1;
    for(int v:mp[x])
    {
        if(dfn[v]==0)
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(dfn[x]==low[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            instk[top]=0;
            siz[scccnt]++;
            scc[top]=scccnt;
            s.pop();
        }while(top!=x);
    }
}
int du[10010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j:mp[i])
        {
            if(scc[i]!=scc[j])
            {
                du[scc[j]]++;
            }
        }
    }
    int cnt=0,ans;
    for(int i=1;i<=scccnt;i++)
    {
        if(du[i]==0)
        {
            ans=siz[i];
            cnt++;
        }
    }
    if(cnt!=1)
    {
        printf("0");
        return 0;
    }
    printf("%d",ans);
    return 0;
}
